export interface FundsTransferRequest {
    ccy: string;
    amt: string;
    from: '6' | '18';
    to: '6' | '18';
    subAcct?: string;
    type?: '0' | '1' | '2' | '3' | '4';
    loanTrans?: boolean;
    clientId?: string;
    omitPosRisk?: string;
}
export interface WithdrawRequest {
    ccy: string;
    amt: string;
    dest: '3' | '4';
    toAddr: string;
    /**
     * Address type:
     * - 1: wallet address, email, phone, or login account name
     * - 2: UID (only for whitelisted users; applicable only when dest=3)
     */
    toAddrType?: '1' | '2';
    chain?: string;
    areaCode?: string;
    clientId?: string;
    rcvrInfo?: {
        walletType: 'exchange' | 'private';
        exchId?: string;
        rcvrFirstName?: string;
        rcvrLastName?: string;
        rcvrCountry?: string;
        rcvrCountrySubDivision?: string;
        rcvrTownName?: string;
        rcvrStreetName?: string;
    };
}
export interface FundingRateRequest {
    instId: string;
    before?: string;
    after?: string;
    limit?: string;
}
export interface GetDepositWithdrawStatusRequest {
    wdId?: string;
    txId?: string;
    ccy?: string;
    to?: string;
    chain?: string;
}
export interface GetDepositHistoryRequest {
    ccy?: string;
    depId?: string;
    fromWdId?: string;
    txId?: string;
    type?: '3' | '4';
    state?: '0' | '1' | '2' | '8' | '11' | '12' | '13' | '14' | '17';
    after?: string;
    before?: string;
    limit?: string;
}
